/**
 * User notification preferences model.
 *
 * WARNING: This model was designed assuming email-only notifications.
 * SMS support has now been added (see src/adapters/sms.adapter.ts),
 * which means this model needs to be updated to support per-channel
 * preferences. Specifically:
 *
 * TODO(multi-channel-preferences):
 * - Add an SmsPreferences interface (enabled, subscribedCategories)
 *   mirroring EmailPreferences.
 * - Add an `sms: SmsPreferences` field to UserPreferences.
 * - Add UpdateSmsPreferencesInput for the update path.
 * - Update DEFAULT_SMS_PREFERENCES and createDefaultPreferences().
 * - Update PreferencesService to add shouldSendSms() check.
 * - Update NotificationService.send() to call shouldSendSms() for
 *   the 'sms' channel, mirroring the existing email preference check.
 *
 * Until then, SMS notifications bypass preference checks and are
 * always delivered when the SMS adapter is registered.
 */

import type { NotificationType } from './notification.js';

/**
 * How often batched/digest emails are sent.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** Delivery frequency for non-urgent notifications. */
  frequency: EmailFrequency;
  /** Notification categories the user is subscribed to. */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  /** The user ID these preferences belong to. */
  id: string;
  /** User ID (same as id — preferences are keyed by user). */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** When the preferences were created. */
  createdAt: Date;
  /** When the preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'account-updated',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Create a default UserPreferences for a given user.
 */
export function createDefaultPreferences(userId: string): UserPreferences {
  const now = new Date();
  return {
    id: userId,
    userId,
    email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
    createdAt: now,
    updatedAt: now,
  };
}

