/**
 * User notification preferences model.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 * Each channel has its own enabled flag and subscribed categories.
 * Email additionally supports a delivery frequency setting.
 *
 * Opt-out model: all channels default to enabled with all categories
 * subscribed. Users without stored preferences receive everything.
 */

import type { NotificationType } from './notification.js';

/**
 * How often batched/digest emails are sent.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** Delivery frequency for non-urgent notifications. */
  frequency: EmailFrequency;
  /** Notification categories the user is subscribed to. */
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification preferences.
 */
export interface SmsPreferences {
  /** Whether SMS notifications are enabled at all. */
  enabled: boolean;
  /** Notification categories the user is subscribed to via SMS. */
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification preferences.
 */
export interface WebhookPreferences {
  /** Whether webhook notifications are enabled at all. */
  enabled: boolean;
  /** Notification categories the user is subscribed to via webhook. */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  /** The user ID these preferences belong to. */
  id: string;
  /** User ID (same as id — preferences are keyed by user). */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** SMS notification settings. */
  sms: SmsPreferences;
  /** Webhook notification settings. */
  webhook: WebhookPreferences;
  /** When the preferences were created. */
  createdAt: Date;
  /** When the preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating SMS preferences. All fields optional.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating webhook preferences. All fields optional.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'account-updated',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default SMS preferences for new users.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: true,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default webhook preferences for new users.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: true,
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Create a default UserPreferences for a given user.
 */
export function createDefaultPreferences(userId: string): UserPreferences {
  const now = new Date();
  return {
    id: userId,
    userId,
    email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
    sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
    webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
    createdAt: now,
    updatedAt: now,
  };
}

