/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for per-channel notification preferences
 * (email, SMS, webhook) and shouldSend*() checks that the
 * NotificationService uses before dispatching a notification.
 *
 * Default behaviour: if a user has no stored preferences, they
 * receive all notifications on all channels (opt-out model).
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { createDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns defaults if none exist.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return createDefaultPreferences(userId);
  }

  /**
   * Get preferences only if they have been explicitly saved.
   * Returns undefined when the user has never customised preferences.
   */
  getSavedPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Ensure a user has stored preferences. Creates defaults if needed.
   */
  private ensurePreferences(userId: string): UserPreferences {
    let prefs = this.repository.findByUserId(userId);
    if (!prefs) {
      prefs = createDefaultPreferences(userId);
      this.repository.save(prefs);
      this.logger.info(`Created default preferences for user ${userId}`);
    }
    return prefs;
  }

  /**
   * Update email preferences for a user.
   * Creates defaults first if the user has no stored preferences.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    const prefs = this.ensurePreferences(userId);

    const updatedEmail = {
      ...prefs.email,
      ...input,
    };

    const updated = this.repository.update(userId, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated email preferences for user ${userId}`);
    return updated;
  }

  /**
   * Update SMS preferences for a user.
   * Creates defaults first if the user has no stored preferences.
   */
  updateSmsPreferences(
    userId: string,
    input: UpdateSmsPreferencesInput,
  ): UserPreferences {
    const prefs = this.ensurePreferences(userId);

    const updatedSms = {
      ...prefs.sms,
      ...input,
    };

    const updated = this.repository.update(userId, {
      sms: updatedSms,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated SMS preferences for user ${userId}`);
    return updated;
  }

  /**
   * Update webhook preferences for a user.
   * Creates defaults first if the user has no stored preferences.
   */
  updateWebhookPreferences(
    userId: string,
    input: UpdateWebhookPreferencesInput,
  ): UserPreferences {
    const prefs = this.ensurePreferences(userId);

    const updatedWebhook = {
      ...prefs.webhook,
      ...input,
    };

    const updated = this.repository.update(userId, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated webhook preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   *
   * Returns true when:
   * 1. The user has no stored preferences (defaults = all enabled), OR
   * 2. Email is enabled AND the notification type is in their subscribed categories.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    // No stored preferences — default is to send everything.
    if (!prefs) {
      return true;
    }

    if (!prefs.email.enabled) {
      this.logger.info(
        `Email disabled for user ${userId}, suppressing ${notificationType}`,
      );
      return false;
    }

    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(
        `User ${userId} unsubscribed from ${notificationType} via email, suppressing`,
      );
      return false;
    }

    return true;
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   *
   * Returns true when:
   * 1. The user has no stored preferences (defaults = all enabled), OR
   * 2. SMS is enabled AND the notification type is in their subscribed categories.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    if (!prefs) {
      return true;
    }

    if (!prefs.sms.enabled) {
      this.logger.info(
        `SMS disabled for user ${userId}, suppressing ${notificationType}`,
      );
      return false;
    }

    if (!prefs.sms.subscribedCategories.includes(notificationType)) {
      this.logger.info(
        `User ${userId} unsubscribed from ${notificationType} via SMS, suppressing`,
      );
      return false;
    }

    return true;
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   *
   * Returns true when:
   * 1. The user has no stored preferences (defaults = all enabled), OR
   * 2. Webhook is enabled AND the notification type is in their subscribed categories.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    if (!prefs) {
      return true;
    }

    if (!prefs.webhook.enabled) {
      this.logger.info(
        `Webhook disabled for user ${userId}, suppressing ${notificationType}`,
      );
      return false;
    }

    if (!prefs.webhook.subscribedCategories.includes(notificationType)) {
      this.logger.info(
        `User ${userId} unsubscribed from ${notificationType} via webhook, suppressing`,
      );
      return false;
    }

    return true;
  }

  /**
   * Check whether a notification should be sent on a given channel.
   * Dispatches to the appropriate channel-specific check.
   */
  shouldSend(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    switch (channel) {
      case 'email':
        return this.shouldSendEmail(userId, notificationType);
      case 'sms':
        return this.shouldSendSms(userId, notificationType);
      case 'webhook':
        return this.shouldSendWebhook(userId, notificationType);
      default:
        // Unknown channels are allowed through by default (opt-out model).
        return true;
    }
  }

  /**
   * Reset a user's preferences to defaults (deletes stored record).
   */
  resetPreferences(userId: string): void {
    this.repository.delete(userId);
    this.logger.info(`Reset preferences for user ${userId}`);
  }
}

