import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
  });

  describe('getPreferences', () => {
    it('should return defaults when user has no stored preferences', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return stored preferences when they exist', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily' });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.frequency).toBe('daily');
    });

    it('should return default SMS preferences for new users', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return default webhook preferences for new users', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });
  });

  describe('getSavedPreferences', () => {
    it('should return undefined when no preferences have been saved', () => {
      expect(service.getSavedPreferences('user-1')).toBeUndefined();
    });

    it('should return preferences after they have been saved', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.getSavedPreferences('user-1')).toBeDefined();
    });
  });

  describe('updateEmailPreferences', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        frequency: 'weekly',
      });
      expect(prefs.email.frequency).toBe('weekly');
      expect(prefs.email.enabled).toBe(true); // default kept
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should disable email notifications', () => {
      const prefs = service.updateEmailPreferences('user-1', { enabled: false });
      expect(prefs.email.enabled).toBe(false);
    });

    it('should update subscribed categories', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order-confirmation'],
      });
      expect(prefs.email.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should merge updates without overwriting other fields', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily' });
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['welcome'],
      });
      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.subscribedCategories).toEqual(['welcome']);
    });

    it('should update the updatedAt timestamp', () => {
      const first = service.updateEmailPreferences('user-1', { frequency: 'daily' });
      const firstUpdatedAt = first.updatedAt;

      // Small delay to ensure different timestamp
      const second = service.updateEmailPreferences('user-1', { frequency: 'weekly' });
      expect(second.updatedAt.getTime()).toBeGreaterThanOrEqual(firstUpdatedAt.getTime());
    });

    it('should not affect SMS or webhook preferences', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      const prefs = service.getPreferences('user-1');
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.webhook.enabled).toBe(true);
    });
  });

  describe('updateSmsPreferences', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateSmsPreferences('user-1', { enabled: false });
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update subscribed categories', () => {
      const prefs = service.updateSmsPreferences('user-1', {
        subscribedCategories: ['order-confirmation'],
      });
      expect(prefs.sms.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should merge updates without overwriting other fields', () => {
      service.updateSmsPreferences('user-1', {
        subscribedCategories: ['welcome'],
      });
      const prefs = service.updateSmsPreferences('user-1', { enabled: false });
      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.subscribedCategories).toEqual(['welcome']);
    });

    it('should not affect email or webhook preferences', () => {
      service.updateSmsPreferences('user-1', { enabled: false });
      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.webhook.enabled).toBe(true);
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateWebhookPreferences('user-1', { enabled: false });
      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should update subscribed categories', () => {
      const prefs = service.updateWebhookPreferences('user-1', {
        subscribedCategories: ['order-status-update'],
      });
      expect(prefs.webhook.subscribedCategories).toEqual(['order-status-update']);
    });

    it('should not affect email or SMS preferences', () => {
      service.updateWebhookPreferences('user-1', { enabled: false });
      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.sms.enabled).toBe(true);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (defaults)', () => {
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and type is subscribed', () => {
      service.updateEmailPreferences('user-1', {
        enabled: true,
        subscribedCategories: ['order-confirmation', 'welcome'],
      });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when notification type is not subscribed', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['welcome'],
      });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return true for subscribed types even with reduced list', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order-status-update'],
      });
      expect(service.shouldSendEmail('user-1', 'order-status-update')).toBe(true);
    });
  });

  describe('shouldSendSms', () => {
    it('should return true when no preferences exist (defaults)', () => {
      expect(service.shouldSendSms('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when SMS is disabled', () => {
      service.updateSmsPreferences('user-1', { enabled: false });
      expect(service.shouldSendSms('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when notification type is not subscribed', () => {
      service.updateSmsPreferences('user-1', {
        subscribedCategories: ['welcome'],
      });
      expect(service.shouldSendSms('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled and type is subscribed', () => {
      service.updateSmsPreferences('user-1', {
        subscribedCategories: ['order-confirmation'],
      });
      expect(service.shouldSendSms('user-1', 'order-confirmation')).toBe(true);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return true when no preferences exist (defaults)', () => {
      expect(service.shouldSendWebhook('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when webhook is disabled', () => {
      service.updateWebhookPreferences('user-1', { enabled: false });
      expect(service.shouldSendWebhook('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when notification type is not subscribed', () => {
      service.updateWebhookPreferences('user-1', {
        subscribedCategories: ['welcome'],
      });
      expect(service.shouldSendWebhook('user-1', 'order-confirmation')).toBe(false);
    });
  });

  describe('shouldSend (unified)', () => {
    it('should dispatch to email check', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.shouldSend('user-1', 'email', 'welcome')).toBe(false);
    });

    it('should dispatch to sms check', () => {
      service.updateSmsPreferences('user-1', { enabled: false });
      expect(service.shouldSend('user-1', 'sms', 'welcome')).toBe(false);
    });

    it('should dispatch to webhook check', () => {
      service.updateWebhookPreferences('user-1', { enabled: false });
      expect(service.shouldSend('user-1', 'webhook', 'welcome')).toBe(false);
    });

    it('should allow unknown channels through by default', () => {
      expect(service.shouldSend('user-1', 'in-app', 'welcome')).toBe(true);
    });
  });

  describe('resetPreferences', () => {
    it('should remove stored preferences', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.getSavedPreferences('user-1')).toBeDefined();

      service.resetPreferences('user-1');
      expect(service.getSavedPreferences('user-1')).toBeUndefined();
    });

    it('should restore default behaviour after reset', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);

      service.resetPreferences('user-1');
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should restore all channels to defaults after reset', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      service.updateSmsPreferences('user-1', { enabled: false });
      service.updateWebhookPreferences('user-1', { enabled: false });

      service.resetPreferences('user-1');

      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendSms('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendWebhook('user-1', 'welcome')).toBe(true);
    });
  });

  describe('cross-channel independence', () => {
    it('should allow disabling one channel while keeping others enabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      service.updateSmsPreferences('user-1', { enabled: true });
      service.updateWebhookPreferences('user-1', { enabled: true });

      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
      expect(service.shouldSendSms('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendWebhook('user-1', 'welcome')).toBe(true);
    });

    it('should allow different subscribed categories per channel', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order-confirmation', 'welcome'],
      });
      service.updateSmsPreferences('user-1', {
        subscribedCategories: ['order-confirmation'],
      });
      service.updateWebhookPreferences('user-1', {
        subscribedCategories: ['order-status-update'],
      });

      // order-confirmation: email yes, sms yes, webhook no
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSendSms('user-1', 'order-confirmation')).toBe(true);
      expect(service.shouldSendWebhook('user-1', 'order-confirmation')).toBe(false);

      // welcome: email yes, sms no, webhook no
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendSms('user-1', 'welcome')).toBe(false);
      expect(service.shouldSendWebhook('user-1', 'welcome')).toBe(false);

      // order-status-update: email no, sms no, webhook yes
      expect(service.shouldSendEmail('user-1', 'order-status-update')).toBe(false);
      expect(service.shouldSendSms('user-1', 'order-status-update')).toBe(false);
      expect(service.shouldSendWebhook('user-1', 'order-status-update')).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);

    const prefsRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
  });

  it('should send notification when user has no preferences (defaults)', async () => {
    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const results = notificationService.getResults();
    expect(results).toHaveLength(1);
    expect(results[0]?.success).toBe(true);
    // Email should have been delivered through the adapter
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const results = notificationService.getResults();
    expect(results).toHaveLength(1);
    expect(results[0]?.success).toBe(true); // suppressed counts as success
    // Email should NOT have been delivered through the adapter
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when type is unsubscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order-status-update'], // NOT 'order-confirmation'
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should send notification when type is subscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order-confirmation'],
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should work without preferences service (backwards compatible)', async () => {
    // Create a service without preferences
    const plainService = new NotificationService(eventBus);
    const plainAdapter = new EmailAdapter();
    plainService.registerAdapter(plainAdapter);

    // Emit directly via send (the event handlers are on the other service)
    const result = await plainService.send({
      type: 'welcome',
      channel: 'email',
      recipient: 'bob@example.com',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-99' },
    });

    expect(result.success).toBe(true);
    expect(plainAdapter.getSentEmails()).toHaveLength(1);
  });
});

describe('NotificationService multi-channel preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);

    emailAdapter = new EmailAdapter();
    smsAdapter = new SmsAdapter();
    webhookAdapter = new WebhookAdapter('https://hooks.example.com/notify');

    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);

    const prefsRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
  });

  it('should suppress SMS when SMS is disabled but allow email', async () => {
    preferencesService.updateSmsPreferences('user-1', { enabled: false });

    // SMS should be suppressed
    const smsResult = await notificationService.send({
      type: 'welcome',
      channel: 'sms',
      recipient: '+15551234567',
      subject: 'Welcome',
      body: 'Hello via SMS',
      metadata: { userId: 'user-1' },
    });

    // Email should go through
    const emailResult = await notificationService.send({
      type: 'welcome',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Hello via email',
      metadata: { userId: 'user-1' },
    });

    expect(smsResult.success).toBe(true); // suppressed counts as success
    expect(smsAdapter.getSentMessages()).toHaveLength(0);

    expect(emailResult.success).toBe(true);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should suppress webhook when webhook is disabled but allow SMS', async () => {
    preferencesService.updateWebhookPreferences('user-1', { enabled: false });

    const webhookResult = await notificationService.send({
      type: 'order-confirmation',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Order',
      body: 'Your order was placed',
      metadata: { userId: 'user-1' },
    });

    const smsResult = await notificationService.send({
      type: 'order-confirmation',
      channel: 'sms',
      recipient: '+15551234567',
      subject: 'Order',
      body: 'Your order was placed',
      metadata: { userId: 'user-1' },
    });

    expect(webhookResult.success).toBe(true);
    expect(webhookAdapter.getSentRequests()).toHaveLength(0);

    expect(smsResult.success).toBe(true);
    expect(smsAdapter.getSentMessages()).toHaveLength(1);
  });

  it('should suppress SMS for unsubscribed notification types', async () => {
    preferencesService.updateSmsPreferences('user-1', {
      subscribedCategories: ['order-confirmation'],
    });

    const result = await notificationService.send({
      type: 'welcome',
      channel: 'sms',
      recipient: '+15551234567',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-1' },
    });

    expect(result.success).toBe(true);
    expect(smsAdapter.getSentMessages()).toHaveLength(0);
  });

  it('should allow all channels when no preferences are stored', async () => {
    const emailResult = await notificationService.send({
      type: 'welcome',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-new' },
    });

    const smsResult = await notificationService.send({
      type: 'welcome',
      channel: 'sms',
      recipient: '+15551234567',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-new' },
    });

    const webhookResult = await notificationService.send({
      type: 'welcome',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-new' },
    });

    expect(emailResult.success).toBe(true);
    expect(smsResult.success).toBe(true);
    expect(webhookResult.success).toBe(true);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
    expect(smsAdapter.getSentMessages()).toHaveLength(1);
    expect(webhookAdapter.getSentRequests()).toHaveLength(1);
  });

  it('should suppress all channels when all are disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    preferencesService.updateSmsPreferences('user-1', { enabled: false });
    preferencesService.updateWebhookPreferences('user-1', { enabled: false });

    await notificationService.send({
      type: 'welcome',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-1' },
    });

    await notificationService.send({
      type: 'welcome',
      channel: 'sms',
      recipient: '+15551234567',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-1' },
    });

    await notificationService.send({
      type: 'welcome',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Welcome',
      body: 'Hello',
      metadata: { userId: 'user-1' },
    });

    expect(emailAdapter.getSentEmails()).toHaveLength(0);
    expect(smsAdapter.getSentMessages()).toHaveLength(0);
    expect(webhookAdapter.getSentRequests()).toHaveLength(0);
  });

  it('should respect per-channel category subscriptions independently', async () => {
    // Email subscribes to order-confirmation only
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order-confirmation'],
    });
    // SMS subscribes to welcome only
    preferencesService.updateSmsPreferences('user-1', {
      subscribedCategories: ['welcome'],
    });

    // Send order-confirmation to both channels
    await notificationService.send({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Order',
      body: 'Confirmed',
      metadata: { userId: 'user-1' },
    });
    await notificationService.send({
      type: 'order-confirmation',
      channel: 'sms',
      recipient: '+15551234567',
      subject: 'Order',
      body: 'Confirmed',
      metadata: { userId: 'user-1' },
    });

    // Email should send (subscribed), SMS should suppress (not subscribed)
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
    expect(smsAdapter.getSentMessages()).toHaveLength(0);
  });
});

