import type {
  UserPreferences,
  EmailPreferences,
  SmsPreferences,
  WebhookPreferences,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import {
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
  ALL_NOTIFICATION_CATEGORIES,
} from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const email = JSON.parse(record['email'] as string) as {
      enabled: boolean;
      frequency: string;
      subscribedCategories: string[];
    };

    // Backward compatibility: older records may not have sms/webhook fields.
    const sms = record['sms']
      ? (JSON.parse(record['sms'] as string) as { enabled: boolean; subscribedCategories: string[] })
      : { enabled: DEFAULT_SMS_PREFERENCES.enabled, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] };

    const webhook = record['webhook']
      ? (JSON.parse(record['webhook'] as string) as { enabled: boolean; subscribedCategories: string[] })
      : { enabled: DEFAULT_WEBHOOK_PREFERENCES.enabled, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] };

    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: email.enabled,
        frequency: email.frequency as EmailPreferences['frequency'],
        subscribedCategories: email.subscribedCategories as NotificationType[],
      },
      sms: {
        enabled: sms.enabled,
        subscribedCategories: sms.subscribedCategories as NotificationType[],
      },
      webhook: {
        enabled: webhook.enabled,
        subscribedCategories: webhook.subscribedCategories as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      sms: JSON.stringify(entity.sms),
      webhook: JSON.stringify(entity.webhook),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

